class Solution:
    def minDeletionSize(self, strs):
        W = len(strs[0])
        best = 0
        for mask in range(1 << W):
            cols = [j for j in range(W) if mask & (1 << j)]
            ok = True
            for row in strs:
                if any(row[cols[t]] > row[cols[t + 1]] for t in range(len(cols) - 1)):
                    ok = False
                    break
            if ok:
                best = max(best, len(cols))
        return W - best

