class Solution:
    def minDeletionSize(self, strs):
        W = len(strs[0])
        dp = [1] * W
        for i in range(W):
            for j in range(i):
                if all(row[j] <= row[i] for row in strs):
                    dp[i] = max(dp[i], dp[j] + 1)
        return W - max(dp)

