var minDeletionSize = function(strs) {
    const W = strs[0].length;
    const dp = new Array(W).fill(1);
    for (let i = 0; i < W; i++) {
        for (let j = 0; j < i; j++) {
            let ok = true;
            for (const row of strs) {
                if (row[j] > row[i]) { ok = false; break; }
            }
            if (ok) dp[i] = Math.max(dp[i], dp[j] + 1);
        }
    }
    return W - Math.max(...dp);
};
